namespace sv_e100bf32e061415ea4f91726246f76b9.Client;

public sealed class UserInfo
{
    public required string Email { get; set; }
    public required string[] Roles { get; set; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_e100bf32e061415ea4f91726246f76b9.Client;

/// <summary>
/// Client-side AuthenticationStateProvider that reads the persisted user info
/// supplied by the server during prerendering via PersistentComponentState.
/// This ensures auth state survives the Server → WebAssembly handoff.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            _authenticationStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authenticationStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, authenticationType: nameof(PersistentAuthenticationStateProvider)))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_e100bf32e061415ea4f91726246f76b9.Client;

namespace sv_e100bf32e061415ea4f91726246f76b9;

/// <summary>
/// Server-side AuthenticationStateProvider that creates a hardcoded user
/// and persists the identity via PersistentComponentState so the WebAssembly
/// client can pick it up after the interactive runtime activates.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private static readonly string[] Roles = ["User", "Editor"];
    private const string Email = "bob@example.com";

    private readonly PersistentComponentState _state;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState state)
    {
        _state = state;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        // Return the hardcoded authenticated user.
        if (_authenticationStateTask is null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, Email),
                new(ClaimTypes.Email, Email),
            };

            foreach (var role in Roles)
            {
                claims.Add(new Claim(ClaimTypes.Role, role));
            }

            var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
            _authenticationStateTask = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }

        return _authenticationStateTask;
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
        NotifyAuthenticationStateChanged(_authenticationStateTask);
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authenticationStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirst(ClaimTypes.Email)?.Value;
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            if (email is not null)
            {
                _state.PersistAsJson(nameof(UserInfo), new UserInfo
                {
                    Email = email,
                    Roles = roles,
                });
            }
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

@page "/profile"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <p><strong>Roles:</strong></p>
        <ul>
            @foreach (var role in context.User.FindAll(System.Security.Claims.ClaimTypes.Role))
            {
                <li>@role.Value</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not logged in.</p>
    </NotAuthorized>
</AuthorizeView>

@page "/editor"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@rendermode InteractiveAuto
@attribute [Authorize(Roles = "Editor")]

<PageTitle>Editor</PageTitle>

<h1>Editor</h1>

<AuthorizeView Roles="Editor">
    <Authorized>
        <p>Welcome to the editor page, @context.User.Identity?.Name!</p>
    </Authorized>
    <NotAuthorized>
        <p>Access denied. You do not have the Editor role.</p>
    </NotAuthorized>
</AuthorizeView>

@page "/viewer"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Viewer</PageTitle>

<h1>Viewer</h1>

<AuthorizeView>
    <Authorized>
        <p>Welcome, @context.User.Identity?.Name! You are authenticated.</p>
    </Authorized>
    <NotAuthorized>
        <p>You must be logged in to view this page.</p>
    </NotAuthorized>
</AuthorizeView>

