    <Authorized>
        <p>Welcome to the editor page, @context.User.Identity?.Name!</p>
    </Authorized>
    <NotAuthorized>
        <p>Access denied. You do not have the Editor role.</p>
    </NotAuthorized>
</AuthorizeView>

@page "/viewer"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Viewer</PageTitle>

<h1>Viewer</h1>

<AuthorizeView>
    <Authorized>
        <p>Welcome, @context.User.Identity?.Name! You are authenticated.</p>
    </Authorized>
    <NotAuthorized>
        <p>You must be logged in to view this page.</p>
    </NotAuthorized>
</AuthorizeView>

